import pytest
import requests

def test_allergy_code_single_character_boundary(
    clinician_auth_token, patient_id, fhir_base_url
):
    headers = {"Authorization": f"Bearer {clinician_auth_token}",
               "Content-Type": "application/fhir+json"}

    payload = {
        "resourceType": "AllergyIntolerance",
        "clinicalStatus": {"coding": [{"code": "active"}]},
        "patient": {"reference": f"Patient/{patient_id}"},
        "code": {"coding": [{"system": "http://example.org/test-system",
                              "code": "X"}]}
    }
    r = requests.post(f"{fhir_base_url}/AllergyIntolerance",
                      json=payload, headers=headers)

    # Server must not crash; only 201 or 422 are acceptable
    assert r.status_code in (201, 422), (
        f"Unexpected status {r.status_code} for single-char code boundary test"
    )
    assert r.status_code != 500
    if r.status_code == 422:
        outcome = r.json()
        assert outcome["resourceType"] == "OperationOutcome"
    if r.status_code == 201:
        assert r.json()["resourceType"] == "AllergyIntolerance"
